import React, { useState } from "react";
import { PHONE_PRIMARY, PHONE_SECONDARY, EMAIL_MAIN, EMAIL_DIRECTOR, WEBSITE, ADDRESS, WA_LINK, WA_PATH, IMGS } from "../../data/constants";
import PageHero from "../ui/PageHero";

export default function Contact() {
  const [sent, setSent] = useState(false);
  const [form, setForm] = useState({ name: "", email: "", phone: "", sub: "Hiring Enquiry", msg: "" });

  const submit = () => {
    if (!form.name || !form.email) { alert("Please fill Name and Email!"); return; }
    setSent(true);
  };

  return (
    <div className="fu" style={{ paddingTop: "clamp(70px,10vw,100px)", background: "#F0F6FF" }}>

      <PageHero label="GET IN TOUCH" title="Let's Talk Talent" sub="Reach out for hiring, software development or payroll enquiries." img={IMGS.hiring} />

      <div style={{ maxWidth: 1280, margin: "0 auto", padding: "clamp(32px,5vw,64px) clamp(16px,4vw,48px)" }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(min(100%,340px),1fr))", gap: "clamp(28px,4vw,52px)" }}>

          {/* ── Left: contact info ── */}
          <div>
            <h2 style={{ fontSize: "clamp(22px,2.5vw,30px)", fontWeight: 900, color: "#0284C7", marginBottom: 28, letterSpacing: -0.5, borderBottom: "3px solid #CC0000", paddingBottom: 12, display: "inline-block" }}>Contact Information</h2>
            {[
              ["📞", "Phone",    PHONE_PRIMARY + " / " + PHONE_SECONDARY],
              ["📧", "Email",    EMAIL_MAIN],
              ["👤", "Director", EMAIL_DIRECTOR],
              ["📍", "Office",   ADDRESS],
              ["🌐", "Website",  WEBSITE],
            ].map(([ic, label, val]) => (
              <div key={label} style={{ display: "flex", gap: 14, marginBottom: 20, paddingBottom: 20, borderBottom: "1px solid #DBEAFE" }}>
                <div style={{ width: 46, height: 46, background: "linear-gradient(135deg,#0284C7,#0369A1)", borderRadius: 13, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 19, flexShrink: 0 }}>{ic}</div>
                <div>
                  <div style={{ fontSize: 9.5, color: "#0284C7", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 4 }}>{label}</div>
                  <div style={{ fontSize: 13.5, color: "#0F172A", fontWeight: 600, lineHeight: 1.6 }}>{val}</div>
                </div>
              </div>
            ))}

            {/* WhatsApp strip */}
            <div onClick={() => window.open(WA_LINK, "_blank")} style={{ background: "linear-gradient(135deg,#25D366,#1DAA54)", borderRadius: 18, padding: "20px 24px", display: "flex", alignItems: "center", gap: 14, cursor: "pointer", boxShadow: "0 4px 24px rgba(37,211,102,.25)", transition: "transform .2s" }}
              onMouseEnter={e => e.currentTarget.style.transform = "translateY(-2px)"}
              onMouseLeave={e => e.currentTarget.style.transform = "translateY(0)"}>
              <svg width="28" height="28" viewBox="0 0 24 24" fill="white"><path d={WA_PATH} /></svg>
              <div>
                <div style={{ color: "#fff", fontWeight: 900, fontSize: 15 }}>WhatsApp Your Resume</div>
                <div style={{ color: "rgba(255,255,255,.82)", fontSize: 12.5, marginTop: 2, fontWeight: 400 }}>+91 9869043500 · Reply within 24 hrs</div>
              </div>
            </div>
          </div>

          {/* ── Right: form ── */}
          <div style={{ background: "#fff", borderRadius: 26, padding: "clamp(24px,4vw,44px)", boxShadow: "0 4px 40px rgba(2,132,199,.12)", border: "1px solid #BFDBFE", borderTop: "5px solid #CC0000" }}>
            {sent ? (
              <div style={{ textAlign: "center", padding: "clamp(32px,5vw,52px) 0" }}>
                <div style={{ width: 80, height: 80, borderRadius: "50%", background: "linear-gradient(135deg,#0284C7,#0369A1)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 34, margin: "0 auto 22px", color: "#fff" }}>✓</div>
                <h2 style={{ fontSize: "clamp(22px,3vw,32px)", fontWeight: 900, color: "#0284C7", marginBottom: 10, letterSpacing: -0.5 }}>Message Sent!</h2>
                <p style={{ color: "#64748B", fontSize: 15, fontWeight: 400 }}>We'll get back to you within 24 hours.</p>
                <button className="btn-primary" style={{ marginTop: 24 }} onClick={() => setSent(false)}>Send Another</button>
              </div>
            ) : (
              <>
                <h3 style={{ fontSize: "clamp(18px,2.5vw,26px)", fontWeight: 900, color: "#0284C7", marginBottom: 24, letterSpacing: -0.5 }}>Send Us a Message</h3>

                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))", gap: 13, marginBottom: 13 }}>
                  {[["name","Full Name"], ["email","Email Address"]].map(([k, pl]) => (
                    <div key={k}>
                      <label style={{ display: "block", fontSize: 9.5, color: "#0284C7", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>{pl}</label>
                      <input className="inp" placeholder={pl} value={form[k]} onChange={e => setForm({ ...form, [k]: e.target.value })} />
                    </div>
                  ))}
                </div>

                <div style={{ marginBottom: 13 }}>
                  <label style={{ display: "block", fontSize: 9.5, color: "#0284C7", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Phone Number</label>
                  <input className="inp" placeholder="Your phone number" value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} />
                </div>

                <div style={{ marginBottom: 13 }}>
                  <label style={{ display: "block", fontSize: 9.5, color: "#0284C7", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Subject</label>
                  <select className="inp" value={form.sub} onChange={e => setForm({ ...form, sub: e.target.value })}>
                    {["Hiring Enquiry","IT Recruitment","Non-IT Recruitment","Software Development","Payroll Services","BPO Services","General Enquiry"].map(o => <option key={o}>{o}</option>)}
                  </select>
                </div>

                <div style={{ marginBottom: 24 }}>
                  <label style={{ display: "block", fontSize: 9.5, color: "#0284C7", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Message</label>
                  <textarea className="inp" rows={5} style={{ resize: "vertical" }} placeholder="Tell us about your requirement..." value={form.msg} onChange={e => setForm({ ...form, msg: e.target.value })} />
                </div>

                <button className="btn-primary" style={{ width: "100%", justifyContent: "center", padding: 15, fontSize: 14, background: "linear-gradient(135deg,#CC0000,#990000)" }} onClick={submit}>
                  Send Message →
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}